const prefix = env.get('CONTEXT_PREFIX') || '';

if (flow.get(`${prefix}initialized`)) {
    return [msg, null];
}
if (flow.get(`${prefix}degraded`)) {
    return null;
}
const buffer = flow.get(`${prefix}state_buffer`) || [];
buffer.push(msg);
flow.set(`${prefix}state_buffer`, buffer);
if (!flow.get(`${prefix}check_running`)) {
    flow.set(`${prefix}check_running`, true);
    flow.set(`${prefix}retries`, 0);
    return [null, msg];
}

return null;

const prefix = env.get('CONTEXT_PREFIX') || '';
const maxRetries = env.get('MAX_RETRIES') || 20;
const retries = flow.get(`${prefix}retries`) || 0;

if (global.get('initializers.ready', 'initializers') === true) {
    flow.set(`${prefix}check_running`, false);
    return [msg, null];
}
if (retries >= maxRetries) {
    flow.set(`${prefix}check_running`, false);
    msg.timedOut = true;
    return [null, msg];
}
flow.set(`${prefix}retries`, retries + 1);
return [null, msg];

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}initialized`, true);
flow.set(`${prefix}degraded`, false);
flow.set(`${prefix}check_running`, false);

const buffer = flow.get(`${prefix}state_buffer`) || [];
flow.set(`${prefix}state_buffer`, []);

for (const bufferedMsg of buffer) {
    node.send([bufferedMsg, null]);
}

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}degraded`, true);
flow.set(`${prefix}initialized`, false);
flow.set(`${prefix}check_running`, false);
flow.set(`${prefix}state_buffer`, []);

msg.timedOut = true;
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers');
const previous = flow.get('node-red_ha_status') || 'unknown';
const current = (msg.statusCode === 200) ? 'healthy' : 'unhealthy';

flow.set('node-red_ha_status', current);

const fill = current === 'healthy' ? 'green' : 'red';
const shape = current === 'healthy' ? 'dot' : 'ring';
node.status({ fill, shape, text: formatStatus(current.toUpperCase()) });

msg.haStatus = current;
msg.transition = { from: previous, to: current };

if (current === 'healthy') {
    return [msg, null];
}
return [null, msg];

// Inline formatStatus — essential service pattern
const ts = new Date().toLocaleString('en-US', {
    month: 'short', day: 'numeric',
    hour: 'numeric', minute: '2-digit', hour12: true
});

const group = msg.group || 'Unspecified';

msg.topic = 'highland/event/log';
msg.payload = {
    timestamp: new Date().toISOString(),
    system: 'node_red',
    source: 'health_checks',
    level: 'ERROR',
    message: `Health check failed for ${group}: ${msg.error.message}`,
    context: {
        node: msg.error.source.name,
        type: msg.error.source.type
    }
};

node.status({ fill: 'red', shape: 'dot', text: `ERROR at: ${ts}` });
return msg;

